        'about_form' => 'Découvrez notre plateforme crypto – inscription gratuite',
        'about_gain_access' => 'DÉBLOQUEZ Floventra POUR LE CRYPTO MAINTENANT',
        'about_benefits' => '<h2 class="gb-headline gb-headline-70fe3449 gb-headline-text">
