        'contact_keywords' => 'Support crypto, Floventra, Suisse, Bitcoin, Ethereum, Altcoins, Investissement alimenté par l’IA',
        'contact_h1' => 'Connectez-vous avec Floventra pour un support crypto',
        'contact_desc' => '<h2 class="gb-headline gb-headline-47e629b7 gb-headline-text">Nous sommes là pour votre parcours crypto</h2>
