        'about_form' => 'Explore Our Crypto Platform – Free Sign-Up',
        'about_gain_access' => 'UNLOCK Floventra FOR CRYPTO NOW',
        'about_benefits' => '<h2 class="au-headline au-headline-70fe3449 au-headline-text">
